skeletons.template:
class MyClass {
  // Public instance variable
  String name;

  // Private instance variable (by convention)
  int _internalValue;

  // Constructor
  MyClass(this.name, this._internalValue);

  // Public method
  void greet() {
    print('Hello, my name is $name.');
  }

  // A method demonstrating access to a private variable
  void showInternalValue() {
     print('The internal value is $_internalValue.');
  }
}
